const intentType = String($json.intent_type || $json.payload?.intent_type || '').toLowerCase();
const approvalTypes = new Set([
  'draft_strategy_message_offer',
  'draft_strategy_pricing_experiment',
  'draft_strategy_promotion_plan'
]);
if (!approvalTypes.has(intentType)) return [];
return [{
  json: {
    ...$json,
    intent_type: intentType,
    approval_scope: 'offer_promo',
    approval_reason: 'Offer, pricing, and promotion strategy intents require human approval before execution.',
    approval_status: 'pending_approval',
    required_approver_roles: ['crm_owner', 'growth_lead']
  }
}];

const status = String($json.status || $json.gate_status || '').toLowerCase();
if (status === 'approved' || status === 'auto_approved') { return [{json:$json}]; }
return [];
